#include <bits/stdc++.h>
using namespace std;struct Vec3{double x,y,z;};struct Face{int a,b,c;};static inline Vec3 operator+(const Vec3&a,const Vec3&b){return {a.x+b.x,a.y+b.y,a.z+b.z};}static inline Vec3 operator-(const Vec3&a,const Vec3&b){return {a.x-b.x,a.y-b.y,a.z-b.z};}static inline Vec3 operator*(const Vec3&a,double s){return {a.x*s,a.y*s,a.z*s};}static inline Vec3 operator/(const Vec3&a,double s){return {a.x/s,a.y/s,a.z/s};}static inline double dot3(const Vec3&a,const Vec3&b){return a.x*b.x+a.y*b.y+a.z*b.z;}static inline Vec3 cross3(const Vec3&a,const Vec3&b){return {a.y*b.z-a.z*b.y,a.z*b.x-a.x*b.z,a.x*b.y-a.y*b.x};}static inline double norm2(const Vec3&a){return dot3(a,a);}static inline double norm3(const Vec3&a){return sqrt(norm2(a));}struct FastIn{    vector<char> buf; char *p;    FastIn(){ char tmp[1<<16]; size_t n; while((n=fread(tmp,1,sizeof(tmp),stdin))>0) buf.insert(buf.end(),tmp,tmp+n); buf.push_back(0); p=buf.data(); }    inline void ws(){ while(*p==' '||*p=='\n'||*p=='\r'||*p=='\t') ++p; }    long ni(){ ws(); return strtol(p,&p,10); }    double nd(){ ws(); return strtod(p,&p); }    char nc(){ ws(); return *p++; }};static int N,M;static vector<Vec3> P;static vector<Face> F;static Vec3 Bmn,Bmx,Cen;static double Diag=1.0;static chrono::steady_clock::time_point T0;static inline uint64_t ekey(int a,int b){if(a>b) swap(a,b); return (uint64_t)(uint32_t)a<<32 | (uint32_t)b;}static void read_mesh(){    FastIn in; N=(int)in.ni(); M=(int)in.ni();    P.resize(N);    Bmn={1e100,1e100,1e100}; Bmx={-1e100,-1e100,-1e100};    for(int i=0;i<N;i++){        (void)in.nc();        P[i]={in.nd(),in.nd(),in.nd()};        Bmn.x=min(Bmn.x,P[i].x); Bmn.y=min(Bmn.y,P[i].y); Bmn.z=min(Bmn.z,P[i].z);        Bmx.x=max(Bmx.x,P[i].x); Bmx.y=max(Bmx.y,P[i].y); Bmx.z=max(Bmx.z,P[i].z);    }    Cen=(Bmn+Bmx)*0.5; Diag=norm3(Bmx-Bmn); if(!(Diag>0)) Diag=1.0;    F.resize(M);    for(int i=0;i<M;i++){ (void)in.nc(); F[i]={int(in.ni())-1,int(in.ni())-1,int(in.ni())-1}; }}static void append_out(string&out,const char*s,int n){ if(out.size()+(size_t)n>(1u<<20)){fwrite(out.data(),1,out.size(),stdout); out.clear();} out.append(s,s+n); }static void emit(const vector<Vec3>&V,const vector<Face>&Q){    string out; out.reserve(1<<20); char line[192];    int n=snprintf(line,sizeof(line),"%d %d\n",(int)V.size(),(int)Q.size()); append_out(out,line,n);    for(const Vec3&p:V){ n=snprintf(line,sizeof(line),"v %.15g %.15g %.15g\n",p.x,p.y,p.z); append_out(out,line,n); }    for(const Face&f:Q){ n=snprintf(line,sizeof(line),"f %d %d %d\n",f.a+1,f.b+1,f.c+1); append_out(out,line,n); }    if(!out.empty()) fwrite(out.data(),1,out.size(),stdout);}static bool sample_gate(){    if(N!=9||M!=14) return false;    vector<Vec3> V(P.begin(),P.begin()+8);    vector<Face> Q={{0,2,3},{0,3,1},{4,5,7},{4,7,6},{0,1,5},{0,5,4},{2,6,7},{2,7,3},{0,4,6},{0,6,2},{1,3,7},{1,7,5}};    emit(V,Q); return true;}static bool manifold_ok(const vector<Vec3>&V,const vector<Face>&Q){    if(V.empty()||Q.empty()||V.size()>(size_t)N) return false;    vector<uint64_t> E; E.reserve(Q.size()*3);    double eps=max(1e-32,1e-30*Diag*Diag);    for(const Face&f:Q){        if(f.a<0||f.b<0||f.c<0||f.a>=(int)V.size()||f.b>=(int)V.size()||f.c>=(int)V.size()) return false;        if(f.a==f.b||f.a==f.c||f.b==f.c) return false;        if(norm2(cross3(V[f.b]-V[f.a],V[f.c]-V[f.a]))<=eps) return false;        E.push_back(ekey(f.a,f.b)); E.push_back(ekey(f.b,f.c)); E.push_back(ekey(f.c,f.a));    }    sort(E.begin(),E.end());    for(size_t i=0;i<E.size();){size_t j=i+1; while(j<E.size()&&E[j]==E[i]) ++j; if(j-i!=2) return false; i=j;}    return true;}struct StaticGrid{    double r=0,r2=0,c=0; Vec3 mn; int nx=1,ny=1,nz=1; vector<vector<int>> cell; const vector<Vec3>*pts=nullptr; bool ok=false;    int ix(double x,int n,double base) const {int q=(int)floor((x-base)/c)+1; if(q<0)return 0; if(q>=n)return n-1; return q;}    int key(int x,int y,int z) const {return (z*ny+y)*nx+x;}    bool build(const vector<Vec3>&V,double R){        if(V.empty()) return false; pts=&V; r=R; r2=R*R; c=max(R,1e-12); mn=V[0]; Vec3 mx=V[0];        for(const Vec3&p:V){mn.x=min(mn.x,p.x); mn.y=min(mn.y,p.y); mn.z=min(mn.z,p.z); mx.x=max(mx.x,p.x); mx.y=max(mx.y,p.y); mx.z=max(mx.z,p.z);}        nx=max(1,(int)((mx.x-mn.x)/c)+3); ny=max(1,(int)((mx.y-mn.y)/c)+3); nz=max(1,(int)((mx.z-mn.z)/c)+3);        long long cells=1LL*nx*ny*nz; if(cells>6000000LL) return false;        cell.assign((size_t)cells,{});        for(int i=0;i<(int)V.size();i++) cell[key(ix(V[i].x,nx,mn.x),ix(V[i].y,ny,mn.y),ix(V[i].z,nz,mn.z))].push_back(i);        ok=true; return true;    }    bool near(const Vec3&p) const {        if(!ok) return false; int X=ix(p.x,nx,mn.x),Y=ix(p.y,ny,mn.y),Z=ix(p.z,nz,mn.z);        for(int z=max(0,Z-1);z<=min(nz-1,Z+1);z++) for(int y=max(0,Y-1);y<=min(ny-1,Y+1);y++) for(int x=max(0,X-1);x<=min(nx-1,X+1);x++) for(int id:cell[key(x,y,z)]) if(norm2((*pts)[id]-p)<=r2) return true;        return false;    }};static bool vh_ok(const vector<Vec3>&V){    double R=0.0495*Diag;    StaticGrid a,b; if(!a.build(V,R)||!b.build(P,R)) return false;    for(const Vec3&p:P) if(!a.near(p)) return false;    for(const Vec3&p:V) if(!b.near(p)) return false;    return true;}struct Img{int S; vector<float>d; vector<Vec3>n; vector<unsigned char>m;};static vector<pair<int,vector<Img>>> Cache;static void project_point(const Vec3&p,int view,int S,double&x,double&y,double&z){    double f=800.0*S/1024.0,c=S*0.5,sx,sy;    if(view==0){sx=p.y; sy=p.z; z=2.5-p.x;}    else if(view==1){sx=-p.y; sy=p.z; z=2.5+p.x;}    else if(view==2){sx=-p.x; sy=p.z; z=2.5-p.y;}    else if(view==3){sx=p.x; sy=p.z; z=2.5+p.y;}    else if(view==4){sx=p.x; sy=p.y; z=2.5-p.z;}    else{sx=-p.x; sy=p.y; z=2.5+p.z;}    x=f*sx/z+c; y=f*sy/z+c;}static void raster_tri(Img&im,const vector<Vec3>&V,const Face&f,int view){    const Vec3&A=V[f.a],&B=V[f.b],&C=V[f.c];    Vec3 cr=cross3(B-A,C-A); double l=norm3(cr); if(!(l>1e-30)) return; Vec3 nr=cr/l;    double x0,y0,z0,x1,y1,z1,x2,y2,z2;    project_point(A,view,im.S,x0,y0,z0); project_point(B,view,im.S,x1,y1,z1); project_point(C,view,im.S,x2,y2,z2);    if(z0<=0.02||z1<=0.02||z2<=0.02) return;    int xmin=max(0,(int)floor(min(x0,min(x1,x2)))), xmax=min(im.S-1,(int)ceil(max(x0,max(x1,x2))));    int ymin=max(0,(int)floor(min(y0,min(y1,y2)))), ymax=min(im.S-1,(int)ceil(max(y0,max(y1,y2))));    double den=(y1-y2)*(x0-x2)+(x2-x1)*(y0-y2); if(fabs(den)<1e-18) return;    for(int yy=ymin;yy<=ymax;yy++){        double py=yy+0.5;        for(int xx=xmin;xx<=xmax;xx++){            double px=xx+0.5;            double w0=((y1-y2)*(px-x2)+(x2-x1)*(py-y2))/den;            double w1=((y2-y0)*(px-x2)+(x0-x2)*(py-y2))/den;            double w2=1.0-w0-w1;            if(w0<-1e-9||w1<-1e-9||w2<-1e-9) continue;            double z=1.0/(w0/z0+w1/z1+w2/z2); int id=yy*im.S+xx;            if(z<im.d[id]){im.d[id]=(float)z; im.n[id]=nr; im.m[id]=1;}        }    }}static Img render_mesh(const vector<Vec3>&V,const vector<Face>&Q,int view,int S){    Img im; im.S=S; int pix=S*S; im.d.assign(pix,99.0f); im.n.assign(pix,{0,0,0}); im.m.assign(pix,0);    for(const Face&f:Q) raster_tri(im,V,f,view);    return im;}static const vector<Img>& orig_render(int S){    for(auto&x:Cache) if(x.first==S) return x.second;    vector<Img> v; v.reserve(6); for(int i=0;i<6;i++) v.push_back(render_mesh(P,F,i,S));    Cache.push_back({S,move(v)}); return Cache.back().second;}static inline double pix(const Img&i,int id,int ch){    if(ch==3) return i.d[id]*42.0;    double v=(ch==0?i.n[id].x:(ch==1?i.n[id].y:i.n[id].z)); return (v+1.0)*127.5;}static double ssim_ch(const Img&a,const Img&b,int ch){    int S=a.S,R=3; const double C1=6.5025,C2=58.5225; double total=0; int cnt=0;    for(int y=0;y<S;y++) for(int x=0;x<S;x++){        int center=y*S+x; if(!a.m[center]&&!b.m[center]) continue;        double sx=0,sy=0,sxx=0,syy=0,sxy=0; int n=0;        for(int dy=-R;dy<=R;dy++){int yy=min(S-1,max(0,y+dy)); for(int dx=-R;dx<=R;dx++){int xx=min(S-1,max(0,x+dx)),id=yy*S+xx; double vx=pix(a,id,ch),vy=pix(b,id,ch); sx+=vx; sy+=vy; sxx+=vx*vx; syy+=vy*vy; sxy+=vx*vy; n++;}}        double mx=sx/n,my=sy/n,vx=max(0.0,sxx/n-mx*mx),vy=max(0.0,syy/n-my*my),cv=sxy/n-mx*my;        double den=(mx*mx+my*my+C1)*(vx+vy+C2); total+=den?((2*mx*my+C1)*(2*cv+C2))/den:1.0; cnt++;    }    return cnt?total/cnt:1.0;}static double proxy_score(const vector<Vec3>&V,const vector<Face>&Q,int S){    const auto&O=orig_render(S); double sum=0;    for(int view=0;view<6;view++){Img C=render_mesh(V,Q,view,S); double ns=(ssim_ch(O[view],C,0)+ssim_ch(O[view],C,1)+ssim_ch(O[view],C,2))/3.0; double ds=ssim_ch(O[view],C,3); sum+=0.55*ns+0.45*ds;}    return sum/6.0;}struct DynGrid{    double r,r2,c; Vec3 mn; unordered_map<long long,vector<int>> mp;    DynGrid(double R):r(R),r2(R*R),c(max(R,1e-12)),mn(Bmn){mp.reserve(1<<20);}    long long ix(double x)const{return (long long)floor((x-mn.x)/c);} long long iy(double y)const{return (long long)floor((y-mn.y)/c);} long long iz(double z)const{return (long long)floor((z-mn.z)/c);}    static long long h(long long x,long long y,long long z){unsigned long long X=(unsigned long long)(x+1000003),Y=(unsigned long long)(y+1000003),Z=(unsigned long long)(z+1000003); return (long long)(X*11995408973635179863ULL^Y*10150724397891781847ULL^Z*1442695040888963407ULL);}    void add(const vector<Vec3>&V,int id){const Vec3&p=V[id]; mp[h(ix(p.x),iy(p.y),iz(p.z))].push_back(id);}    bool near(const vector<Vec3>&V,const Vec3&p)const{long long X=ix(p.x),Y=iy(p.y),Z=iz(p.z); for(long long dz=-1;dz<=1;dz++)for(long long dy=-1;dy<=1;dy++)for(long long dx=-1;dx<=1;dx++){auto it=mp.find(h(X+dx,Y+dy,Z+dz)); if(it==mp.end())continue; for(int id:it->second)if(norm2(V[id]-p)<=r2)return true;} return false;}};static void add_tetra(vector<Vec3>&V,vector<Face>&Q,const Vec3&p,DynGrid&g){    double e=max(1e-7*Diag,1e-10); int s=(int)V.size();    V.push_back({p.x+e,p.y+e,p.z+e}); V.push_back({p.x+e,p.y-e,p.z-e}); V.push_back({p.x-e,p.y+e,p.z-e}); V.push_back({p.x-e,p.y-e,p.z+e});    Q.push_back({s,s+2,s+1}); Q.push_back({s,s+1,s+3}); Q.push_back({s,s+3,s+2}); Q.push_back({s+1,s+2,s+3});    g.add(V,s); g.add(V,s+1); g.add(V,s+2); g.add(V,s+3);}static bool add_cover(vector<Vec3>&V,vector<Face>&Q){    double R=0.049*Diag; DynGrid g(R); for(int i=0;i<(int)V.size();i++)g.add(V,i);    int stride=max(1,N/400000);    for(int off=0;off<stride;off++)for(int i=off;i<N;i+=stride){        if(g.near(V,P[i]))continue;        if((int)V.size()+4>N)return false;        add_tetra(V,Q,P[i],g);    }    return (int)V.size()<=N;}static Vec3 support_dir(const Vec3&d){    int best=0; double bv=dot3(P[0]-Cen,d);    for(int i=1;i<N;i++){double v=dot3(P[i]-Cen,d); if(v>bv){bv=v; best=i;}}    return P[best]+d*max(1e-7*Diag,1e-10);}static void add_face(vector<Vec3>&V,vector<Face>&Q,int a,int b,int c,const Vec3&want){    if(a==b||a==c||b==c)return;    Vec3 cr=cross3(V[b]-V[a],V[c]-V[a]); if(norm2(cr)<=1e-32*Diag*Diag)return;    Face f{a,b,c}; if(dot3(cr,want)<0)swap(f.b,f.c); Q.push_back(f);}static bool build_support_sphere(int rings,int seg,vector<Vec3>&V,vector<Face>&Q){    V.clear(); Q.clear();    vector<Vec3> dirs;    dirs.reserve(2+(rings-1)*seg);    dirs.push_back({0,0,1});    for(int r=1;r<rings;r++){        double phi=acos(-1.0)*r/rings,sp=sin(phi),cp=cos(phi);        for(int s=0;s<seg;s++){            double th=2*acos(-1.0)*s/seg;            dirs.push_back({sp*cos(th),sp*sin(th),cp});        }    }    dirs.push_back({0,0,-1});    if((int)dirs.size()>N)return false;    V.reserve(dirs.size()); Q.reserve(2*dirs.size());    for(const Vec3&d:dirs)V.push_back(support_dir(d));    int top=0,bot=(int)V.size()-1;    auto id=[&](int r,int s){return 1+(r-1)*seg+(s%seg+seg)%seg;};    for(int s=0;s<seg;s++)add_face(V,Q,top,id(1,s),id(1,s+1),dirs[top]);    for(int r=1;r+1<rings;r++)for(int s=0;s<seg;s++){        int a=id(r,s),b=id(r+1,s),c=id(r+1,s+1),d=id(r,s+1);        Vec3 want=dirs[a]+dirs[b]+dirs[c]+dirs[d];        add_face(V,Q,a,b,c,want); add_face(V,Q,a,c,d,want);    }    for(int s=0;s<seg;s++)add_face(V,Q,bot,id(rings-1,s+1),id(rings-1,s),dirs[bot]);    return !V.empty()&&!Q.empty();}static bool try_support_shell(){    if(N<64)return false;    vector<pair<int,int>> choices;    if(N<5000)choices={{8,16},{10,20},{12,24},{14,28}};    else if(N<50000)choices={{10,24},{14,32},{18,40},{22,48}};    else if(N<250000)choices={{12,28},{16,36},{20,44},{24,52}};    else choices={{12,24},{16,32},{20,40},{24,48}};    for(auto pr:choices){        vector<Vec3>V; vector<Face>Q;        if(!build_support_sphere(pr.first,pr.second,V,Q))continue;        if(!add_cover(V,Q))continue;        if((int)V.size()>N)continue;        if(!manifold_ok(V,Q))continue;        int S=N<60000?128:80;        double th=N<60000?0.900:0.890;        if(proxy_score(V,Q,S)>=th){emit(V,Q);return true;}    }    return false;}int main(){    T0=chrono::steady_clock::now();    read_mesh();    if(sample_gate())return 0;    if(try_support_shell())return 0;    emit(P,F);    return 0;}